using Contoso.Scoring;

namespace Contoso.Scoring.Tests;

[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calculator = new();

    // --- CalculatePercentage ---

    [TestMethod]
    [DataRow(7, 10, 70.0)]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 5, 0.0)]
    [DataRow(1, 3, 33.333333333333336)]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(int correct, int total, double expected)
    {
        var result = _calculator.CalculatePercentage(correct, total);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void CalculatePercentage_Result_IsInValidRange()
    {
        var result = _calculator.CalculatePercentage(3, 7);

        Assert.IsInRange(result, 0.0, 100.0);
        Assert.IsGreaterThan(0.0, result);   // strictly positive for non-zero correct
        Assert.IsLessThan(100.0, result);    // strictly less than 100 when correct < total
    }

    [TestMethod]
    public void CalculatePercentage_AllCorrect_ReturnsExactly100()
    {
        var result = _calculator.CalculatePercentage(20, 20);

        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_NoneCorrect_ReturnsExactly0()
    {
        var result = _calculator.CalculatePercentage(0, 10);

        Assert.AreEqual(0.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(11, 10));
    }

    // --- GetGrade boundary tests ---

    [TestMethod]
    [DataRow(90.0, "A", DisplayName = "90 → A (lower boundary)")]
    [DataRow(100.0, "A", DisplayName = "100 → A")]
    [DataRow(89.99, "B", DisplayName = "89.99 → B (just below A)")]
    [DataRow(80.0, "B", DisplayName = "80 → B (lower boundary)")]
    [DataRow(79.99, "C", DisplayName = "79.99 → C (just below B)")]
    [DataRow(70.0, "C", DisplayName = "70 → C (lower boundary)")]
    [DataRow(69.99, "D", DisplayName = "69.99 → D (just below C)")]
    [DataRow(60.0, "D", DisplayName = "60 → D (lower boundary)")]
    [DataRow(59.99, "F", DisplayName = "59.99 → F (just below D)")]
    [DataRow(0.0, "F", DisplayName = "0 → F")]
    public void GetGrade_AtBoundaries_ReturnsCorrectGrade(double percentage, string expected)
    {
        var grade = _calculator.GetGrade(percentage);

        Assert.AreEqual(expected, grade);
    }

    // --- NormalizeScore ---

    [TestMethod]
    public void NormalizeScore_MidRange_IsInExpectedRange()
    {
        var result = _calculator.NormalizeScore(35.0, 50.0);

        Assert.IsInRange(result, 60.0, 80.0);
        Assert.AreEqual(70.0, result);
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_IsCappedAt100()
    {
        var result = _calculator.NormalizeScore(120.0, 100.0);

        Assert.AreEqual(100.0, result);
        Assert.IsLessThan(101.0, result); // never exceeds 100
    }

    [TestMethod]
    public void NormalizeScore_ZeroRaw_ReturnsZero()
    {
        var result = _calculator.NormalizeScore(0.0, 50.0);

        Assert.AreEqual(0.0, result);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(-1.0, 50.0));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(10.0, 0.0));
    }

    [TestMethod]
    public void NormalizeScore_NegativeMax_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(10.0, -5.0));
    }
}

